const d = $input.item.json;
return { json: {
  lead_id: d.lead_id || '',
  company_id: d.company_id || '',
  company_name: d.company_name || '',
  ico: d.ico || '',
  found: false,
  domain: '',
  source: ''
} };

const be = $input.item.json || {};
const prev = $('Extract Input').first().json;
let website = '';
if (be.www) website = be.www;
else if (be.sidlo && be.sidlo.www) website = be.sidlo.www;

if (!website) {
  return { json: { ...prev, found: false } };
}

let domain = website.replace(/^https?:\/\//i, '').replace(/^www\./i, '').split(/[\/?#]/)[0].trim().toLowerCase();
if (!domain || !/^[a-z0-9.-]+\.[a-z]{2,}$/.test(domain)) {
  return { json: { ...prev, found: false } };
}

return { json: { ...prev, found: true, domain: domain, source: 'ares' } };

const prev = $('Extract Input').first().json;
const searchQuery = encodeURIComponent(prev.company_name);
return { json: { ...prev, _search_url: 'https://www.firmy.cz/hledej?dotaz=' + searchQuery } };

const prev = $('Prepare Firmy Search').first().json;
const html = ($input.first().json.data || $input.first().json || '').toString();

let domain = '';
const urlMatch = html.match(/href="(https?:\/\/(?:www\.)?([a-z0-9.-]+\.[a-z]{2,}))[^"]*"[^>]*class="[^"]*web/i)
  || html.match(/href="(https?:\/\/(?:www\.)?([a-z0-9.-]+\.[a-z]{2,}))"/i);

if (urlMatch && urlMatch[2]) {
  domain = urlMatch[2].toLowerCase();
}

if (!domain) {
  return [{ json: { ...prev, found: false, _search_url: undefined } }];
}

return [{ json: { ...prev, found: true, domain: domain, source: 'firmy', _search_url: undefined } }];

const prev = $('Extract Input').first().json;
function stripDiacritics(s) {
  return s.normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase();
}
const name = stripDiacritics(prev.company_name)
  .replace(/\b(s\.?r\.?o\.?|a\.?s\.?|spol\.?\s*s\s*r\.?\s*o\.?|v\.?o\.?s\.?)\b/gi, '')
  .replace(/[^a-z0-9]/g, '')
  .trim();
if (!name || name.length < 2) {
  return { json: { ...prev, found: false, _dns_candidates: [] } };
}
return { json: { ...prev, _dns_candidates: [name + '.cz', name + '.com'], _dns_index: 0 } };

const prev = $('Generate DNS Candidates').first().json;
const candidates = prev._dns_candidates || [];
const results = $input.all().map(i => i.json);

// Check .cz probe (index 0)
const czStatus = results[0] && results[0].statusCode ? results[0].statusCode : (results[0] && !results[0].error ? 200 : 0);
const comStatus = results[1] && results[1].statusCode ? results[1].statusCode : (results[1] && !results[1].error ? 200 : 0);

// A successful probe: got any HTTP response (even 403/301) means server exists
// Only network errors (timeout, DNS fail) produce no status code
if (czStatus > 0 && czStatus < 500 && candidates[0]) {
  return [{ json: { lead_id: prev.lead_id, company_id: prev.company_id, company_name: prev.company_name, ico: prev.ico, found: true, domain: candidates[0], source: 'dns' } }];
}
if (comStatus > 0 && comStatus < 500 && candidates[1]) {
  return [{ json: { lead_id: prev.lead_id, company_id: prev.company_id, company_name: prev.company_name, ico: prev.ico, found: true, domain: candidates[1], source: 'dns' } }];
}

return [{ json: { lead_id: prev.lead_id, company_id: prev.company_id, company_name: prev.company_name, ico: prev.ico, found: false, domain: '', source: '' } }];

const prev = $('Extract Input').first().json;
const searchQuery = encodeURIComponent(prev.company_name + ' website');
return { json: { ...prev, _ddg_url: 'https://html.duckduckgo.com/html/?q=' + searchQuery } };

const prev = $('Prepare DDG Search').first().json;
const html = ($input.first().json.data || $input.first().json || '').toString();

// Extract result URLs from DuckDuckGo HTML results
// DDG wraps results in <a class="result__a" href="...">
let domain = '';
const resultPattern = /class="result__a"[^>]*href="([^"]+)"/g;
let match;
while ((match = resultPattern.exec(html)) !== null) {
  const url = match[1];
  // Skip DDG internal links
  if (url.includes('duckduckgo.com')) continue;
  // Extract domain
  const domainMatch = url.match(/https?:\/\/(?:www\.)?([a-z0-9.-]+\.[a-z]{2,})/i);
  if (domainMatch && domainMatch[1]) {
    const d = domainMatch[1].toLowerCase();
    // Skip search engines and social media
    if (['google.com','facebook.com','twitter.com','linkedin.com','instagram.com','youtube.com','wikipedia.org','firmy.cz','kurzy.cz','rejstrik.penize.cz','or.justice.cz'].includes(d)) continue;
    domain = d;
    break;
  }
}

// Also try generic URL extraction if class-based didn't work
if (!domain) {
  const genericMatch = html.match(/href="(https?:\/\/(?:www\.)?([a-z0-9.-]+\.[a-z]{2,}))[^"]*"/i);
  if (genericMatch && genericMatch[2]) {
    const d = genericMatch[2].toLowerCase();
    if (!['duckduckgo.com','google.com','facebook.com','twitter.com','linkedin.com'].includes(d)) {
      domain = d;
    }
  }
}

if (!domain) {
  return [{ json: { lead_id: prev.lead_id, company_id: prev.company_id, company_name: prev.company_name, ico: prev.ico, found: false, domain: '', source: '' } }];
}

return [{ json: { lead_id: prev.lead_id, company_id: prev.company_id, company_name: prev.company_name, ico: prev.ico, found: true, domain: domain, source: 'ddg' } }];
